ootprints","label":"步行","value":"高","level":4},{"icon":"cloud-rain","label":"雨天安全性","value":"极佳","level":5},{"icon":"users","label":"家庭适宜度","value":"良好","level":4},{"icon":"gauge","label":"平衡性","value":"均衡","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原华城","alt":"水原华城 — 图库图片 1","caption":"水原华城 — 照片 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield图书馆水原","alt":"Starfield图书馆水原 — gallery image 1","caption":"Starfield图书馆水原 — photo 1"},{"id":3,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 1","caption":"光明洞窟 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原华城","alt":"水原华城 — 图库图片 2","caption":"水原华城 — 照片 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原华城","alt":"水原华城 — 图库图片 3","caption":"水原华城 — 照片 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原华城","alt":"水原华城 — 图库图片 4","caption":"水原华城 — 照片 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原华城","alt":"水原华城 — 图库图片 5","caption":"水原华城 — 照片 5"},{"id":8,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield图书馆水原","alt":"Starfield图书馆水原 — gallery image 2","caption":"Starfield图书馆水原 — photo 2"},{"id":9,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield图书馆水原","alt":"Starfield图书馆水原 — gallery image 3","caption":"Starfield图书馆水原 — photo 3"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield图书馆水原","alt":"Starfield图书馆水原 — gallery image 4","caption":"Starfield图书馆水原 — photo 4"},{"id":11,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 2","caption":"光明洞窟 — photo 2"},{"id":12,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 3","caption":"光明洞窟 — photo 3"},{"id":13,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 4","caption":"光明洞窟 — photo 4"}],"itineraryStops":[{"number":1,"time":"≈ 08:30","duration":"10分钟","name":"首尔出发","category":"接送与出发","description":"从首尔市中心两个集合点之一上车：**弘益大学站8号出口**（弘大区域，首尔地铁2号线/机场快线）或**明洞站2号或4号出口**（首尔地铁4号线）。经京釜高速公路**乘大巴向南约1小时抵达水原**。\n\n全天9小时行程经过精心安排：在游客高峰（约11:00）前率先游览华城（1997年联合国教科文组织世界遗产），随后于下午在星空图书馆享用午餐，最后以光明洞窟的LED艺术作为压轴，傍晚返回首尔。大巴配备空调，大多数座位设有USB充电接口。","highlights":["从弘益大学（2号线）或明洞（4号线）约08:30出发接送","乘大巴经京釜高速公路向南行驶1小时前往水原","9小时行程特别规划，确保在华城游客高峰前完成参观","大巴配备空调 + USB充电"],"timeUsed":["在首尔指定集合点候车（上车约需5分钟）","乘大巴前往水原（路况畅通时约60分钟）"],"whyOnRoute":"09:30抵达水原，距正午游客高峰（约11:00）尚有60至90分钟，可从容游览华城堡垒。全天行程环环相扣——城堡 → 宫殿 → 市场午餐 → 图书馆 → 洞窟——最大程度减少大巴调度转场，并以洞窟稳定精彩的室内节目圆满收官。","visitBasics":{},"convenience":{},"smartNotes":{"tip":"预订时请确认准确的接送时间和集合地点。爬城墙时请携带饮用水、防晒霜和舒适的鞋子，并备一件薄外套以应对洞穴内的低温（全年12°C）。"},"_poi_meta":{"poi_key":"OPS_seoul_pickup_default","verified":false,"match":"operational_default","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational pickup — Seoul departure"},"_role":"pickup"},{"number":2,"time":"≈ 09:30","duration":"60分钟","name":"水原华城","category":"联合国教科文组织世界遗产城堡","description":"**水原华城（수원화성）——1997年列入联合国教科文组织世界遗产名录** — 韩国唯一保留完整原始10卷建设记录的城郭城市（《华城城役仪轨》，2007年单独列入联合国教科文组织世界记忆名录）。**建于1794-1796年，历时2年9个月**，由朝鲜第22代国王正祖（정조，在位\n\n1776-1800年）主导兴建——此举旨在将朝鲜都城从汉阳（首尔）迁至水原，并以此告慰遭赐死的父亲思悼世子。由**丁若镛（정약용，号茶山）**设计——朝鲜实学派（实用主义学问）领军学者兼工程师——融合了朝鲜防御建筑学、中国攻城防御理论与西方新兴筑城科学。\n\n丁若镛发明了**举重机（거중기）滑轮起重装置** ——这是韩国建筑史上首次有据可查的西式现代工程技术应用。\n\n**城墙周长5.74公里，设有41处军事设施**，其中包括**长安门（北主门）——韩国现存最大王室城门**，规模超过首尔崇礼门。\n\n9小时行程路线将穿越**长安门至华西门（西门，国宝第403号）之间最具拍摄价值的1.2公里路段** ——约25-30分钟步行，途经保存最为密集的军事建筑群。\n\n横跨水原川的**华虹门（北水门）**拥有7座拱桥，是拍摄频率最高的建筑。**韩服着装者免费入场 + 每月最后一个周三免费 + 65岁以上老年人免费 + 6岁以下儿童免费** ——对水原家庭出游而言，这是一项相当实惠的福利。","highlights":["**1997年列入联合国教科文组织世界遗产名录** — 拥有原版华城城役仪轨建造记录的韩国唯一城郭城市","由正祖大王主导，建于1794-1796年，历时2年9个月","由丁若镛设计，融合朝鲜、中国与西方筑城科学","《华城城役仪轨》——2007年列入联合国教科文组织世界记忆名录","城墙周长5.74公里，设有41处战略军事设施","长安门北城门——**韩国现存最大王室城门**","长安门→华西门1.2公里导览步行（拍摄点密度最高路段）","华虹门7拱水门——拍摄频率最高的建筑","韩服着装者免费 + 65岁以上老年人免费 + 每月最后一个周三免费"],"timeUsed":["大巴在长安门附近下车（约5分钟）","简短团队说明（约5分钟）","步行长安门→华西门（约25-30分钟）","拍照时间 + 返回车辆集合（约10分钟）","可选华城列车观光小火车 演武台↔八达门（约30分钟单程；成人₩4,000）"],"whyOnRoute":"此行程的联合国教科文组织世界遗产核心景点——韩国唯一保存至今的城郭城市，由正祖大王主导建于1794-1796年。长安门→华西门步行段在60分钟的停留时间内涵盖了密度最高的保存完好军事建筑群，完全适配包含5个主要景点的9小时行程。全程5.74公里环线需耗时2.5小时以上，将占用当天其他文化遗产与现代景点的参观时间。在这份5站行程中，华城作为**上午的核心景点**——5.74公里城墙周长不宜在单次游览中完整绕行，因此一日游形式聚焦于长安门→西将台西段（约25-30分钟步行，保存密度最高）。1801年编纂的**《华城城役仪轨》**建设档案——自2007年列入联合国教科文组织世界记忆名录——详细记录了每块石料、每根梁木及每位工匠的工资，为韩国战争后自1975年起的忠实修复工程提供了依据。丁若镛发明的**举重机（거중기）滑轮起重装置**是朝鲜时代建筑工地上首次有据可查的西方力学工程技术应用，比韩国工业机械化早约120年。","visitBasics":{"hours":"城墙步道全天24小时开放；建议游览时间：夏季09:00-18:00 / 冬季09:00-17:00","closed":"全年开放（华城列车周一休息）","admission":"成人1,000韩元 / 青少年700韩元 / 儿童500韩元（免费：6岁以下儿童、65岁以上老年人、韩服着装者、每月最后一个周三）","walking":"中等难度——城墙部分路段坡度较陡；各城门处有台阶"},"convenience":{"restroom":"位于长安门、华西门、八达门、演武台","parking":"大巴在长安门停车场下车"},"smartNotes":{"photo":"**华虹门（北水门）** 横跨水原川，七拱成排——经典取景地。**长安门（韩国现存最大王室城门）** 黄金时刻。**西将台（西指挥所）** 夕阳映照八达山。","facilities":"各主要城门均设有游客服务中心；全程设有英韩双语指示牌","tip":"在行宫广场租借韩服可免费入场城堡及宫殿。长安门 → 华西门段的文化遗产密度最高。"},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原华城","caption":"水原华城 — 照片 1","alt":"水原华城 — 图库图片 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原华城","caption":"水原华城 — 照片 2","alt":"水原华城 — 图库图片 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原华城","caption":"水原华城 — 照片 3","alt":"水原华城 — 图库图片 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原华城","caption":"水原华城 — 照片 4","alt":"水原华城 — 图库图片 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原华城","caption":"水原华城 — 照片 5","alt":"水原华城 — 图库图片 5"}]},{"number":3,"time":"≈ 10:45","duration":"60分钟","name":"华城行宫","category":"朝鲜王朝行宫","description":"**华城行宫（화성행궁）——韩国现存规模最大的行宫（离宫）** — 由正祖大王主持修建，与华城城墙同期兴建（1789-1796年）。\n\n**行宫**是王室出巡、战时避难或举行特殊仪式时使用的临时/离宫；华城行宫在规模上超越温阳、北汉山、南汉山行宫。正祖大王修建此处，主要是为了在祭扫被赐死的父亲思悼世子之墓（显隆园，即今融陵，位于南方4公里处）时留宿过夜——在位期间共进行了**13次**这样的巡游。\n\n其中最著名的是**1795年王室巡游**（随行人员6,000名，马匹1,400匹），以庆祝惠庆宫洪氏六十寿辰——此次盛事详载于**《园幸乙卯整理仪轨》，该文献自2007年起列入联合国教科文组织世界记忆遗产**。行宫原有**576间（房间/结构开间）** — 堪称一座完整的微缩皇家宫殿。\n\n日本殖民时期（1910-1945年），行宫被改建为水原道立医院与警察署，大部分建筑遭到破坏。1996年启动修复工程；第一期于2003年完工（奉寿堂、洛南轩、长安轩、维与宅），第二期于2009年完工（迂华馆御膳厨房、新丰楼城门）。\n\n**重要历史说明：洛南轩（낙남헌）是唯一保存自1796年原始建筑的殿堂** — 日本殖民当局将其改作警察署办公用途，但未将其拆除。因此它是该遗址上唯一一座**真正的**原始建筑，其余所有建筑均为1996年后的重建。\n\n**王室卫兵换岗仪式**在新丰楼城门举行 — **周二至周日上午11:00**，约15分钟，**免费**。行程安排10:45抵达，恰好赶上11:00仪式（视当日星期而定）。韩剧**《大长今》（대장금，2003年）**曾在此取景拍摄 — 这部脍炙人口的朝鲜题材剧集在 MBC 创下约57%的最高收视率。","highlights":["**韩国现存规模最大的行宫（离宫）** — 原有576间","正祖大王13次亲赴此地，悼念被赐死的父亲思悼世子","**洛南轩 = 唯一保存至今的1796年原始建筑**（其余均为重建）","**王室卫兵换岗仪式 周二至周日上午11:00，新丰楼（免费）**","1795年王室巡游 — 联合国教科文组织世界记忆遗产","韩剧《大长今》取景地","穿韩服者及65岁以上老人免费","**洛南轩（낙남헌）是唯一保存自1796年原始建筑的殿堂** — 日本殖民时期当局将其改作警察署办公用途，但未将其拆除；今日行宫内可见的其他所有建筑，均为依据《华城城役仪轨》（2007年列入联合国教科文组织世界记忆遗产）于1996年后重建而成","**576间（房间/结构开间）** = 韩国现存**规模最大**的行宫（离宫） — 正祖大王专为在祭扫被赐死的父亲思悼世子之墓（显隆园，南方4公里处）时留宿过夜而修建；正祖在1795年至1800年间共进行了13次巡游"],"timeUsed":["距华城城墙（华西门区域）步行5分钟","王室卫兵换岗仪式11:00（周二至周日）—— 约15分钟","奉寿堂 + 洛南轩 + 长安轩参观（约30分钟）","拍照时间 + 返回车辆集合（约10分钟）","可选：新丰楼王室卫兵换岗仪式（周二至周日上午11:00，约15分钟，免费——视天气而定）"],"whyOnRoute":"这座临时王室居所与华城城墙同属联合国教科文组织遗址，两处相距步行仅5分钟。**洛南轩 = 唯一真正的原始建筑**（其余均为1996年后重建）。建议安排在上午11:00王室卫兵换岗仪式前抵达——免费，约15分钟，是本行程中最值得体验的免费项目之一。行宫在华城工程中占据着**历史与情感的核心地位** — 华城城墙（1794-1796年）正是围绕行宫而建，专为护卫正祖大王前往父亲陵寝的孝道巡游。在参观城墙之后游览行宫，能将抽象的军事建筑知识转化为真实的朝鲜王朝宫廷空间体验：同一座**奉寿堂正殿**，于1795年还曾举办正祖大王之母惠庆宫洪氏的豪华六十寿宴（此盛况记录于现存的《仪轨班次图》宫廷画卷之中）。该遗址曾多次出现在韩剧拍摄中，包括《大长今》（2003年）、《成均馆绯闻》（2010年）及《云画的月光》（2016年）。**华城城墙+行宫联票**售价3,500韩元（单独购票合计2,500韩元），使行宫成为当日主线行程中极具性价比的游览选项。","visitBasics":{"hours":"09:00-18:00（最晚入场17:30）；夏季5月至10月夜间开放18:00-21:00","closed":"全年开放","admission":"成人1,500 / 青少年1,000 / 儿童700韩元。华城城墙+行宫联票3,500韩元。穿韩服者及65岁以上老人免费","walking":"轻松——宫殿地面大部分平坦，院落之间有少量台阶"},"convenience":{"restroom":"主入口处、奉寿堂附近、行宫广场","parking":"华城行宫公共停车场；行宫广场收费停车场"},"smartNotes":{"photo":"**奉寿堂正殿** + **洛南轩（1796年唯一保存至今的原始建筑）** + **新丰楼皇家卫队换岗仪式（周二至周日 上午11:00）**。","facilities":"游客服务中心、行宫广场韩服租借（4小时15,000–20,000韩元），向南步行5分钟即达水原统鸡餐厅街。","tip":"**请准时到达，观看周二至周日上午11:00举行的皇家卫队换岗仪式（免费）**。**洛南轩是历史价值最高的景点** —— 唯一未经重建、在日本殖民时期拆毁行动中幸存下来的建筑。周一不建议前往 —— 皇家卫队换岗仪式仅在周二至周日举行。"},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原华城","caption":"水原华城 — 照片 1","alt":"水原华城 — 图库图片"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原华城","caption":"水原华城 — 照片 2","alt":"水原华城 — 图库图片"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原华城","caption":"水原华城 — 照片 3","alt":"水原华城 — 图库图片"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原华城","caption":"水原华城 — 照片 4","alt":"水原华城 — 图库图片"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原华城","caption":"水原华城 — 照片 5","alt":"水原华城 — 图库图片"}]},{"number":4,"time":"≈ 12:30","duration":"90分钟","name":"Starfield图书馆水原","category":"现代文化地标","description":"**Starfield图书馆水原（별마당 도서관 수원）** — 位于**Starfield水原**内，这是新世界集团旗舰\"第二代\"Starfield购物中心，于**2024年1月26日正式开业**，是第五座Starfield购物中心。总建筑面积约334,000平方米，为韩国第二大室内购物中心（仅次于Starfield河南）。由**BCHO Partners（赵秉洙）**联合设计——正是打造2017年COEX原版Starfield图书馆的韩国建筑事务所。\n\n水原图书馆是第二代升级版，**书架高达22米** — 为韩国公共空间中最高的圆柱形书架结构之一；图书馆横跨4层楼（1F-4F中庭通高），馆藏约**7万册图书与杂志**，涵盖韩文及国际出版物、期刊、艺术书籍，以及4楼专属儿童区。\n\n**全年免费向公众开放**，开放时间与商场同步（每日10:00-22:00）。无需图书馆借阅卡，无需购票入场。图书仅供馆内阅览，不可外借。特色亮点：**黑胶唱片试听区**，精选韩国独立音乐及爵士/经典摇滚黑胶唱片；**每月轮换艺术展览**（中庭展区）；以及**春季樱花主题装置（3-4月）** — 中庭内数千朵粉色LED花瓣漫天飞舞，是水原春季最受欢迎的打卡地之一。\n\n周边商场配套：**Eatopia美食广场（B1F）**，汇聚30余家餐厅；**Aquafield水原水上乐园+韩式温泉（B1-2F）**（需另行购票）；**玩具王国（4F，韩国最大玩具店）**；**CGV/MEGABOX双影院综合体**。\n\n**免费Starfield接驳巴士**从水原站4号出口发车，每10-15分钟一班 — 是从公共交通换乘的最便捷方式。行程中的**休整站点** — 室内舒适环境，在前往光明洞窟（约30分钟大巴车程）前帮助调整游览节奏。\n\n**咖啡休息 + 图书馆打卡拍照 + 商场购物** — 专为轻松过渡而设计，而非另一个高强度景点。","highlights":["**新世界旗舰第二代Starfield购物中心 — 2024年1月26日开业**","BCHO Partners操刀设计（同为原版COEX Starfield图书馆的设计方）","**四层楼高、22米书架** — 韩国最高书架结构之一","约7万册图书与杂志，**免费**开放阅览","黑胶唱片试听休闲区","樱花LED花瓣主题装置（3-4月）","Eatopia美食广场、Aquafield水上乐园、玩具王国、CGV+MEGABOX双影院","从水原站4号出口乘免费Starfield接驳巴士（约10分钟）","**加拿大小说家兼设计师Douglas Coupland打造的屋顶装置艺术\"行星\"** — 水原专属限定（首尔COEX店无此装置）；将Starfield水原定位为新世界图书馆购物中心模式的**\"第二代\"旗舰**，由**BCHO Partners（赵秉洙）**主导设计，而非常遭误归功的荷兰建筑事务所MVRDV"],"timeUsed":["从八达门广场乘大巴约15分钟车程至Starfield","商场 + 图书馆参观游览（约45分钟）","咖啡休息或逛街购物（约20分钟）","返回大巴集合（约10分钟）","可选项目：黑胶唱片咖啡休闲厅（5楼，约₩18,500，含饮品 + 耳机 + 黑胶唱片机使用权限；约30-45分钟）"],"whyOnRoute":"游览古城堡、宫殿与市场午餐后的\"现代韩国\"对比体验。新世界旗舰第二代Starfield购物中心于2024年1月26日正式开业；四层楼高、22米书架的图书馆是最具建筑震撼力的核心空间。**全室内休整站** — 有效规避下午天气风险，在前往光明洞窟工业遗址终章之前，提供真正跨年龄层的多元体验。Starfield图书馆是**首尔大都会圈（首尔市中心以外）最受Instagram打卡热捧的室内空间**（依据2024-25年韩国旅游媒体调查数据）— 22米书架（对比首尔COEX的13米）跨越商场4F至7F，形成连通中庭通高空间。**免费入场、无需会员资格、全程可拍照、商场全区免费进入** — 零门槛打卡拍摄点，毗邻咖啡餐饮区（B1F的Eatopia美食广场汇聚30余家韩式及国际餐厅）。从水原站出发：可乘免费Starfield接驳巴士（水原站4号出口，每10-15分钟一班），或乘坐地铁1号线至华西站1/4号出口（步行约8分钟）。商场营业时间**每日10:00-22:00**，图书馆全程随商场同步开放。","visitBasics":{"hours":"商场每日10:00-22:00；图书馆开放时间与商场同步","closed":"每月1-2天休馆日（通常为周一 — 请提前在线确认）","admission":"图书馆免费；商场全区免费入场；Aquafield需另行购票，约25,000-35,000韩元","walking":"无障碍设施完善 — 各楼层均设自动扶梯与电梯；全面支持轮椅及婴儿车通行"},"convenience":{"restroom":"每层楼均设有多处卫生间；配备亲子友好设施","parking":"地下停车场约5,000个车位；购物满30,000韩元可享前3小时免费停车；设有大巴停车专区（适合团体）"},"smartNotes":{"photo":"**图书馆中庭22米高书架**，可从4楼俯瞰。黑胶唱片休息区，营造复古氛围。中庭樱花主题装置（3月至4月）。圣诞树装饰（12月）。","facilities":"B1层Eatopia美食广场、4层玩具王国、B1-2层Aquafield水上乐园、T-Joy + CGV + MEGABOX影院、免费WiFi、多语种客服、退税服务台。","tip":"**图书馆免费入场**——极具性价比的景点。**22米高书架＝韩国最高**（向游客重点介绍，令人印象深刻）。**3至4月樱花主题装置**为当季必看亮点。避开周六下午（人流高峰期）。请提前在线确认Starfield每月休馆日期。"},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["Starfield official","VisitKorea","Shinsegae press","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield图书馆水原","caption":"Starfield图书馆水原 — photo 1","alt":"Starfield图书馆水原 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield图书馆水原","caption":"Starfield图书馆水原 — photo 2","alt":"Starfield图书馆水原 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield图书馆水原","caption":"Starfield图书馆水原 — photo 3","alt":"Starfield图书馆水原 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield图书馆水原","caption":"Starfield图书馆水原 — photo 4","alt":"Starfield图书馆水原 — gallery image 4"}]},{"number":5,"time":"≈ 15:30","duration":"100分钟","name":"光明洞窟","category":"工业遗址主题洞窟","description":"**光明洞窟（광명동굴）** — 原为**金、银、铜、锌矿**，于**日本殖民时期1912年**开凿，持续开采运营60年，直至1972年。在其运营期间，该矿共产出黄金52公斤、白银6,070公斤、铜1,247吨、锌3,247吨——是日本殖民时期对朝鲜半岛重要矿产资源的大规模掠夺。\n\n采矿停止后，废弃的矿洞被用作**虾酱（새우젓）发酵储存**设施约40年——洞窟内稳定的约12°C温度与高湿度，使其成为韩式腌渍海鲜（젓갈）熟成的理想场所。\n\n**2011年，光明市以43亿韩元**从私人业主手中购入该洞窟，并于2011年8月作为**韩国首个政府所有的洞窟旅游景点**重新对外开放。荣获**2014年韩国旅游明星奖（韩国旅游界奥斯卡）**——成为首个获此殊荣的城市政府开发景点。\n\n**隧道总长7.8公里**，分多层；**约2公里向公众开放**，设有多个主题分区。**全年恒温约12°C（54°F）**——夏季天然凉爽（是逃离韩国酷暑的热门去处），冬季则比室外温暖。\n\n**请携带薄外套。** **主题分区包括**：**洞窟水族馆**（韩国最深的室内淡水水族馆）；**红酒洞窟**（韩国最大的地下酒窖，储有200余种韩国及进口葡萄酒——提供品酒体验，5,000韩元可品尝3款）；**LED艺术隧道**（200米长隧道，设有季节性灯光主题——春季樱花、秋季红叶、冬季冰雪）；**龙马巨龙（Yongmaru）**（41米长玻璃纤维巨龙——韩国洞窟内最高的室内雕塑，社交媒体上最热门的打卡地）；**荧光壁画**（以天然荧光颜料绘制，仅在紫外线/黑光灯下可见）；**音乐厅**（200座经声学优化的演出场馆）；以及**韩国民间故事洞窟主题公园**，设有韩国民间故事人物装置（鬼怪、老虎、兔子）。\n\n曾作为取景地：韩剧**《阿尔罕布拉宫的回忆》（2018年）**、**《花游记》**、**《医生们》**及多档综艺节目。**年游客量约150万人次**（2024年数据）——京畿道收费旅游景点前五之一。\n\n**周一闭馆。** 周二至周日 09:00-18:00（最后入场17:00）。成人10,000 / 青少年5,000 / 儿童3,000韩元。主要路线大部分可供轮椅通行（平坦路面，设有坡道段）。","highlights":["**原为金/银/铜/锌矿** — 由日本殖民政府运营，1912年至1972年","2011年8月作为韩国首个政府所有的洞窟景点重新开放","**荣获2014年韩国旅游明星奖**（韩国旅游界奥斯卡）","隧道总长7.8公里；约2公里对外开放的游览路线","**全年恒温约12°C** — 请携带薄外套","**41米玻璃纤维巨龙（龙马）** — 韩国洞窟内最高的室内雕塑","红酒洞窟 — 韩国最大的地下酒窖（200余种葡萄酒；品酒5,000韩元）","LED艺术隧道 + 荧光壁画 + 音乐厅 + 洞窟水族馆","取景地：《阿尔罕布拉宫的回忆》（2018年）、《花游记》","**周一闭馆** — 周二至周日 09:00-18:00","主要路线可供轮椅通行"],"timeUsed":["从水原星际广场乘大巴约30分钟车程至光明","洞窟入口 + 购票（约10分钟）","主题区游览：水族馆 → LED隧道 → 巨龙 → 音乐厅 → 红酒洞窟 → 民俗公园（约70-80分钟）","可选品酒体验（约15分钟，另需额外付费）","返回大巴集合（约10分钟）"],"whyOnRoute":"当日工业遗产的压轴节目及**全室内终场体验** — 可有效应对傍晚突发天气风险，同时呈现韩国最精彩的洞窟旅游体验。1912-1972年采矿历史 + 2011年重新开放 + LED艺术改造，构成目录中叙事最引人入胜的工业遗产故事。主要路线可供轮椅通行，使其成为当日行程中无障碍设施最完善的遗产景点。光明洞窟**多层次的工业遗产叙事**是其独特卖点：一座开凿于1912年日本殖民时期的金/银/铜/锌矿，持续运营60年（1912-1972年），废弃后被改作虾酱发酵储存设施约40年（得益于洞窟内全年恒定的**约12°C / 54°F温度**及高湿度），最终**于2011年由光明市以43亿韩元**从私人业主手中收购，成为**韩国首个政府所有的洞窟旅游景点**，并荣获2014年韩国旅游明星奖。**2公里的无障碍游览路线**（占隧道总长7.8公里的一部分）在约1.5-2小时内涵盖洞窟水族馆 + 200米LED艺术隧道 + 红酒洞窟（韩国最大地下酒窖，储有200余种韩国及进口葡萄酒）+ 200座音乐厅 + 41米龙马玻璃纤维巨龙（韩国洞窟内最高的室内雕塑）。","visitBasics":{"hours":"周二至周日 09:00-18:00（最后入场17:00）；7月至8月夏季周末延长开放至19:00","closed":"**周一**闭馆（若周一为法定假日则照常开放，顺延次日补休）","admission":"成人10,000 / 青少年5,000 / 儿童3,000韩元；6岁及以下儿童与65岁以上老人**免费**","walking":"轻松至适中 — 主路线约2公里，主要为平坦铺装的洞窟地面；主要路线可供轮椅通行"},"convenience":{"restroom":"分别设于主入口、洞窟中段（音乐厅区域）及出口处","parking":"大型专用停车场（约1,000个车位）；普通车辆2,000韩元 / 大巴5,000韩元；设有团体大巴专用停车区"},"smartNotes":{"photo":"**LED艺术隧道**季节主题灯光（春季樱花、秋季红叶、冬季白雪）— 全场拍照最热门区域。**41米巨龙（龙马）** — 社交媒体热门打卡地。**紫外线下的荧光壁画**。**红酒洞窟酒瓶墙**，展示韩国葡萄酒生产商标签。","facilities":"洞窟餐厅（韩式自助餐，约15,000韩元）、提供洞窟陈酿葡萄酒的咖啡厅、礼品店、Wine Cave品酒室（5,000韩元品尝3款葡萄酒）、音乐厅演出时间表。","tip":"**全年保持12°C——即使夏天也请携带薄外套**。非常适合**夏日逃离韩国酷暑**。**周一不开放**——休馆。**葡萄酒品鉴**（5,000韩元品尝3款）是最被低估的体验——在首尔无处可寻的地方酒庄韩国葡萄酒。最少规划1.5至2小时；若含品酒和音乐厅演出则需2.5小时。"},"_poi_meta":{"poi_key":"gwangmyeong_cave","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-05-21","sources":["VisitKorea","Wikipedia","Gwangmyeong City","KoreaToDo","Korea Tourism Organization (english.visitkorea.or.kr — Gwangmyeong Cave official listing)","Gwangmyeong Cave official (gmcave.gm.go.kr — themed zones + operating hours + admission)","Gwangmyeong City Tourism (gm.go.kr/tour — 2011 city purchase 4.3 billion KRW + Korea''s first govt-owned cave-tourism)","Wikipedia (Gwangmyeong Cave — 1912 Japanese colonial mine + 1972 closure + 7.8 km tunnel total)","Korea Tourism Star Award archive (Gwangmyeong Cave 2014 winner — Best New Tourist Attraction)"]},"image":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","images":["/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp"],"imageCredits":[{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","location":"光明洞窟","caption":"光明洞窟 — photo 1","alt":"光明洞窟 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","location":"光明洞窟","caption":"光明洞窟 — photo 2","alt":"光明洞窟 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","location":"光明洞窟","caption":"光明洞窟 — photo 3","alt":"光明洞窟 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","location":"光明洞窟","caption":"光明洞窟 — photo 4","alt":"光明洞窟 — gallery image 4"}]},{"number":6,"time":"≈ 17:30","duration":"60分钟","name":"返回首尔","category":"返回","description":"乘大巴经**西海岸高速公路**返回首尔市中心（与早上走京釜高速公路的路线不同——环形路线的设计体现了光明位于西侧、水原位于南侧的地理特点）。下车地点与早上的集合点相同（弘益大学站8号出口或明洞站2/4号出口）。视周五傍晚／周末交通状况，通常**18:30-19:00**抵达。","highlights":["从光明经西海岸高速公路返回","在弘益大学或明洞下车","通常18:30-19:00抵达"],"timeUsed":["从光明乘大巴前往首尔（约60分钟）","在指定地点下车"],"whyOnRoute":"返程安排——从光明走西海岸高速公路比从水原折返走京釜高速公路更快，充分利用了当天的地理环线优势。","visitBasics":{},"convenience":{},"smartNotes":{"tip":"最终抵达时间取决于周五傍晚／周末的交通状况；交通繁忙时，下车时间可能额外增加15-20分钟。"},"_poi_meta":{"poi_key":"OPS_return","verified":false,"match":"operational_implicit","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational stop (return)"},"_role":"dropoff"}],"routeFlowStops":[{"name":"首尔","type":"origin","theme":"出发"},{"name":"水原华城","type":"primary","theme":"世界遗产城堡"},{"name":"华城行宫","type":"primary","theme":"历史遗产宫殿"},{"name":"水原星野图书馆","type":"secondary","theme":"现代韩国"},{"name":"光明洞窟","type":"primary","theme":"洞窟"},{"name":"首尔","type":"return","theme":"返回"}],"routePhases":[{"phase":"去程","duration":"约1小时","description":"首尔→水原市，经京釜高速公路。"},{"phase":"历史遗产半程","duration":"≈ 3小时","description":"水原华城城墙与行宫，彼此步行可达。"},{"phase":"现代中心","duration":"≈ 1小时","description":"驾车15分钟前往水原星菲尔德，参观图书馆及商场美食广场。"},{"phase":"地下压轴","duration":"≈ 1.5小时","description":"驾车向西北行驶30分钟，前往光明洞窟，欣赏LED灯光主题乐园。"},{"phase":"返程","duration":"≈ 1小时","description":"光明→首尔，经西海岸高速公路。"}],"routeShapeIntro":{"title":"当日行程安排","subtitle":"这是一条位于首尔南部及西南部的京畿道三角环线：上午游览水原联合国教科文组织世界遗产城市，下午早些时候前往水原旗舰现代购物中心，傍晚以光明转型金矿作为压轴。三种截然不同的公共空间——军事、商业、工业——跨越250年历史，尽在一次大巴环线之旅中。"},"whyTourWorks":{"bestFor":["初次到访该地区的游客","情侣","成人家庭","适应全天行程的活力旅行者","希望游览联合国教科文组织世界遗产景点的旅行者"],"lessIdealFor":["有幽闭恐惧症或害怕密闭空间的旅行者（光明洞窟下层通道狭窄、顶部较低）","无法应对光明洞窟下层主要景点约180级台阶上下的旅行者（无电梯）","在城墙行走有困难的旅行者——城门处有陡坡及阶梯","希望参观首尔市中心宫殿的游客——本次行程全程位于京畿道","必须在周一出行的旅行者——光明洞窟每周一停业维护"],"routeLogicSections":[{"title":"为什么这条路线这样设计","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"比标准水原之旅更丰富多彩","detail":"大多数水原一日游将水原华城、行宫和星空图书馆组合在一起——三个景点相互之间不超过十分钟路程。本线路加入了光明洞窟，这是一处截然不同的风景（地下空间、艺术主题、全年恒温12°C），从水原乘公共交通不易到达。"},{"label":"无论天气如何，室内备选方案始终可靠","detail":"四个主要景点中有两个——星空图书馆和光明洞窟——完全在室内且有空调。华城城墙的步行路段较短，雨天或夏日酷暑均可应对。天气多变时的可靠之选。"},{"label":"免费入场，有偿解说","detail":"星空图书馆可以免费自行参观——但有导游陪同会更有收获，他们能解释为什么一座购物中心会建造这里（新世界百货针对MZ世代的策略）、它与COEX原版有何不同，以及在哪些角度拍照最佳又不打扰读者。"},{"label":"比单一形式的一日游更有趣","detail":"文化遗产游有时会让人感到疲惫不堪，而图书馆与购物中心之旅又可能显得过于轻松。本行程刻意切换节奏——联合国教科文组织认证的城墙、市场美食、现代图书馆，再到LED灯光璀璨的地下主题乐园——让整日行程不会陷入单一节奏。"}]},{"title":"步行强度的实际感受","icon":"footprints","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","items":[{"label":"城墙：最难走的路段","detail":"步行约1公里，城门处坡度较陡且有台阶。必须穿着舒适的鞋子。登高后视野开阔，景色令人心旷神怡，但不适合轮椅通行。"},{"label":"光明洞窟：单程约180级台阶","detail":"前往下层主要景点（葡萄酒洞、黄金瀑布、水上世界）需走台阶，返回亦然。无电梯。行动不便的游客可留在上层参观——那里仍有约40分钟的游览内容。"},{"label":"行宫与星空图书馆：轻松易行","detail":"行宫和星空图书馆地势平坦、便于通行，是城墙与洞窟台阶之间轻松的步行区段。"}]},{"title":"天气与季节变化时","icon":"cloud-sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"夏日酷暑：光明洞窟是避暑胜地","detail":"洞窟内恒温12°C，是炎热天气的绝佳避暑之所。城墙步行时可多利用遮荫休息；市场午餐可移至星空图书馆室内享用。"},{"label":"冬日寒冷：进洞前注意添衣","detail":"当室外气温更低时，12°C已算凉爽。即使在夏天，进入光明洞窟也请带一件薄外套；冬天则需要全程保留外套。"},{"label":"周一不开放","detail":"光明洞窟每周一因维护闭馆，当日行程不开团。如需周一出行，请选择民俗村或卧牛精舍版本的行程。"}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"费用包含","preview":"首尔往返大巴交通、英语导游、水原华城……","content":["首尔往返大巴交通、英语导游、水原华城城墙门票、华城行宫门票、光明洞窟门票。","费用不含：餐食、饮料、洞窟酒庄品酒（可选）、小费。","星野图书馆免费入场。"]},{"id":"pickup","title":"上下车地点","preview":"弘益大学站（8号出口）约08:00，或明洞站（2号或4号出口）约08:30。","content":["弘益大学站（8号出口）约08:00，或明洞站（2号或4号出口）约08:30。","请提前10分钟到达。","不提供酒店接送，仅设固定集合地点。","迟到者无法安排上车，且不予退款。"]},{"id":"walking","title":"步行与地形","preview":"中等难度。","content":["中等难度。","城墙步道需攀登上坡石阶。","光明洞窟通往下层约有180级台阶，需上下折返，且无电梯。","必须穿着舒适的包头步行鞋。","行动不便者不建议参加。"]},{"id":"what","title":"穿着与携带物品","preview":"舒适的步行鞋（运动鞋或登山鞋）、一件薄外套——光明洞窟……","content":["舒适的步行鞋（运动鞋或登山鞋）、一件薄外套——光明洞窟全年温度约12°C，即便夏季也较为凉爽。","冬季游览时，请为城墙部分准备厚外套，洞窟内则穿轻薄衣物。","相机、饮用水、午餐及街头小吃备用现金（预算约₩10,000–₩20,000）。"]},{"id":"cancellation","title":"取消政策","preview":"行程开始前24小时内可免费取消。","content":["行程开始前24小时内可免费取消。","当天取消及未出行均不予退款。","行程周一不运营（光明洞窟休息）。"]},{"id":"children","title":"儿童及无障碍设施","preview":"儿童通常很喜欢这条线路——洞窟灯光、龙雕塑和水世界……","content":["儿童通常很喜欢这条线路——洞窟灯光、龙雕塑和水世界深受家庭游客喜爱。","城墙步道有台阶及不平坦路面。","洞窟内有180多级台阶，不适合行动不便者、携带婴儿车的游客或有幽闭恐惧症的人士。"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"查看季节说明"},"tomorrow":{"temp":"—","label":"查看季节说明"},"_seasonalSummary":"Suwon and Gwangmyeong track Seoul''s weather closely (about 30 km south/southwest). Plan for hot, humid summers and cold, dry winters; the cave is a constant 12°C year-round, providing relief in summer and shelter in winter.","_seasonalTemperatures":[{"season":"Spring (Mar–May)","range":"5–22°C","notes":"Cherry blossoms along the fortress wall in early–mid April."},{"season":"Summer (Jun–Aug)","range":"22–32°C","notes":"Hot and humid; cave is a cool refuge."},{"season":"Autumn (Sep–Nov)","range":"8–22°C","notes":"Best season — clear skies, mild temperatures."},{"season":"Winter (Dec–Feb)","range":"-5 to 6°C","notes":"Cold winds on the fortress wall; library and cave are climate-controlled."}]},"seasonalVariations":[{"season":"春季","description":"华城城墙沿线樱花盛开；洞窟开放春季主题灯光装置。"},{"season":"夏季","description":"洞窟内温度常年12°C，是逃离首尔湿热天气的热门去处；夏季举办水原华城文化节。"},{"season":"秋季","description":"城墙沿线枫叶如火；10月举办盛大的水原华城文化节。"},{"season":"冬季","description":"城墙雪景是经典拍照地；洞窟全年举办不受天气影响的LED主题展。"}],"bookingTrustItems":[{"icon":"check-circle","title":"持牌本地运营商","description":"持有完整保险的韩国授权旅游运营商","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"路线专家","description":"精心设计的行程，绝非千篇一律的环线","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"精心控制的团队规模","description":"最适合路线的团队人数","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"立即","title":"即时确认","detail":"含行程摘要的预订确认"},{"timing":"出发前12小时","title":"12小时行前提醒","detail":"天气更新及路线调整通知"},{"timing":"前一天晚上","title":"最终接送信息","detail":"准确接送时间及司机联系方式"},{"timing":"行程当天早上","title":"当日路线说明","detail":"根据实时路况进行晨间简报"},{"timing":"行程进行中","title":"逐站游览贴士","detail":"每处景点实时导览"},{"timing":"行程结束后","title":"行程后续支持","detail":"后续跟进与推荐建议"}],"staticQuestions":[{"id":"q1","question":"为什么周一不开团？","answer":"光明洞窟每周一因例行维护而关闭。由于洞窟是四大核心景点之一，行程周一不运营。若您希望在周一出行，可考虑仅游水原的行程（华城 + 民俗村 或 华城 + 卧牛精寺）。"},{"id":"q2","question":"门票费用包含在内吗？","answer":"是的——水原华城、华城行宫以及光明洞窟的门票均已包含在内。星空图书馆对所有人免费开放。洞窟酒庄品酒体验（可选）及民俗村内的额外费用需自理。"},{"id":"q3","question":"含午餐吗？","answer":"不包含。午餐通常在自由活动时间内，于星野水原美食广场（种类丰富，₩10,000–₩20,000）或城堡附近的水原小餐馆（水原式排骨或炸鸡）自行解决。"},{"id":"q4","question":"光明洞窟里有多少级台阶？","answer":"下到下层精华区（酒窟、黄金瀑布、水上世界）约需走180级台阶，返回时同样如此。洞内没有电梯。行动不便或有密闭空间恐惧症的游客通常留在上层参观。"},{"id":"q5","question":"洞窟内是暖和还是寒冷？","answer":"凉爽。洞窟内全年保持恒温12°C（54°F）。夏季感觉十分清爽；冬季建议保留一件外套。夏季游客通常会专门为此站带上一件轻薄外套。"},{"id":"q6","question":"这条线路与水原＋民俗村游览有何不同？","answer":"两条线路均包含城墙、行宫和星空图书馆。本线路将其与光明洞窟（一个地下LED主题乐园）相结合。民俗村版本则去掉洞窟，改为参观位于龙仁的韩国民俗村（一座拥有270栋建筑的露天文化遗址公园）。若您偏好多元体验并希望规避天气影响，请选择本线路；若想深度感受朝鲜时代文化遗产，则选择民俗村版本。"},{"id":"first-time","question":"这条线路适合初次游览水原和光明的游客吗？","answer":"是的——非常适合初次到访的游客，可在一天内游览一处UNESCO遗址（华城）、一座朝鲜时代宫殿（行宫）、一处地下主题景点（光明洞窟）以及一处现代网红打卡地（星空图书馆）。行程涵盖四种截然不同的文化体验。注意：该团每逢周一不出发（光明洞窟维护日）。"},{"id":"walking","question":"步行量大吗？","answer":"当天步行量较大，且含一段重型爬梯路段。华城城墙有陡坡和台阶（约步行1公里）。光明洞窟下层精华区需下约180级台阶，返回时同样如此——无电梯。行宫地势较平坦，院内有少量台阶。星空图书馆全程可乘自动扶梯或电梯。全天步行总量约4公里。务必穿着舒适的鞋子，尤其应对洞窟台阶。"},{"id":"family","question":"这条线路适合家庭出游吗？","answer":"适合孩子能够应对城墙步行及光明洞窟台阶的家庭。洞窟深受孩子喜爱——LED立体场景、水上世界水族馆、41米长的龙形雕塑、地下酒庄（仅限成人）以及黄金瀑布。婴儿车不适用于城墙及洞窟台阶区段。洞窟内全年恒温12°C，是绝佳的避暑（或驱寒）休憩站。"},{"id":"seniors","question":"老年人可以舒适地参与吗？","answer":"仅推荐行动灵活、能适应台阶和密闭空间的活力老年人参加。光明洞窟下层的180级台阶无电梯可替代——若无法爬台阶，可仅游览上层（约40分钟内容）。城墙有陡峭路段；较平缓的平坦路段可步行通过。行宫和星空图书馆均无障碍可达。即使在夏季，进入洞窟也请携带一件薄外套。"},{"id":"children","question":"建议的最小参与年龄是多少？","answer":"最适合约10岁及以上的游客。城墙路面不平整，洞窟来回各有180级台阶，且全天行程较长（约9小时）。年龄较小的孩子如能适应爬梯及密闭空间（洞窟下层隧道较为狭窄），也可参加。孩子们通常对洞窟内的地下景点爱不释手——龙形雕塑、水上世界、酒窟（限观赏）。水原街头美食市场适合所有年龄段。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id 在运行时从 Supabase / 环境变量解析，不属于静态 JSONB 的一部分。","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:00","name":"弘大入口站（8号出口）","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"time":"08:30","name":"明洞站（2号或4号出口）","type":"station","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"弘大入口站（8号出口）","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"name":"明洞站（4号出口）","type":"station","lat":37.56099,"lng":126.98619}],"notes":["请提前10分钟到达。迟到者将无法参团，且不予退款。周一不开团（光明洞窟闭馆）。"]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"coach","duration_hours":9,"region_tags":["gyeonggi_suwon","gyeonggi_gwangmyeong","gyeonggi_goyang"],"theme_tags":["unesco","fortress","cave","modern_landmark"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","gwangmyeong_cave","starfield_library_suwon"],"pace_level":0.8,"walking_level":0.8,"scenic_level":0.7,"photo_level":1,"culture_level":0.8,"relax_level":0.6,"first_time_fit":0.85,"family_fit":0.9,"senior_fit":0.85,"couple_fit":0.95,"solo_traveler_fit":0.85,"active_traveler_fit":0.5,"adult_family_fit":1,"family_with_teens_fit":1,"young_kids_fit":0.85,"senior_active_fit":0.65,"senior_general_fit":0.85,"mobility_friendly_fit":0.7,"stroller_fit":0.7,"one_day_fit":1,"same_day_flight_fit":0.3,"rain_fit":0.85,"value_for_money_fit":0.95,"iconic_landmark_fit":0.95,"cafe_fit":0.85,"food_fit":0.65,"nature_fit":0.4,"beach_fit":0,"nightlife_fit":0.05,"shopping_fit":0.7,"no_shopping_fit":0.5,"local_culture_fit":1,"storytelling_fit":1,"unesco_fit":1,"intangible_heritage_fit":0.4,"indoor_ratio":0.55,"weather_sensitivity":0.4,"comfort_level":0.6,"budget_fit":0.7,"premium_fit":0.45,"small_group_fit":1,"private_fit":0.05,"bus_fit":1,"price_band":"mid","pickup_base":"seoul_central","return_time_band":"17:00-18:30","duration_band":"9h","min_recommended_age":10,"hard_constraints":{"avoidIf":["tight_same_day_departure"],"notIdealFor":["very_low_mobility","stroller_heavy_groups"]},"walking_notes":["Active walking day with some stairs and uneven terrain.","Average fitness expected.","Sturdy shoes with grip recommended."],"keywords":["seoul suwon hwaseong gwangmyeong cave starfield library","korea_mainland day tour","korea_mainland small group"],"synonym_hints":["seoul suwon hwaseong gwangmyeong cave star