vel":4},{"icon":"footprints","label":"步行","value":"高","level":4},{"icon":"cloud-rain","label":"雨天安全性","value":"優秀","level":5},{"icon":"users","label":"適合家庭","value":"良好","level":4},{"icon":"gauge","label":"均衡度","value":"均衡","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 1","caption":"水原華城 — 照片 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield圖書館水原店","alt":"Starfield圖書館水原店 — gallery image 1","caption":"Starfield圖書館水原店 — photo 1"},{"id":3,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 1","caption":"光明洞窟 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 2","caption":"水原華城 — 照片 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 3","caption":"水原華城 — 照片 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 4","caption":"水原華城 — 照片 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 5","caption":"水原華城 — 照片 5"},{"id":8,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield圖書館水原店","alt":"Starfield圖書館水原店 — gallery image 2","caption":"Starfield圖書館水原店 — photo 2"},{"id":9,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield圖書館水原店","alt":"Starfield圖書館水原店 — gallery image 3","caption":"Starfield圖書館水原店 — photo 3"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield圖書館水原店","alt":"Starfield圖書館水原店 — gallery image 4","caption":"Starfield圖書館水原店 — photo 4"},{"id":11,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 2","caption":"光明洞窟 — photo 2"},{"id":12,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 3","caption":"光明洞窟 — photo 3"},{"id":13,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","location":"光明洞窟","alt":"光明洞窟 — gallery image 4","caption":"光明洞窟 — photo 4"}],"itineraryStops":[{"number":1,"time":"≈ 08:30","duration":"10 分鐘","name":"首爾出發","category":"接送與出發","description":"在首爾市中心兩個集合地點之一上車：**弘益大學站8號出口**（弘大地區，首爾地鐵2號線／機場快線）或**明洞站2號或4號出口**（首爾地鐵4號線）。沿京釜高速公路搭乘巴士**向南約1小時抵達水原**。\n\n這9小時的行程精心安排：在上午11:00遊客高峰前率先參觀華城（1997年UNESCO世界遺產），接著於下午在星野圖書館享用午餐，最後以光明洞窟的LED藝術燈光秀壓軸，傍晚返回首爾。巴士全程冷氣，大多數座位附設USB充電口。","highlights":["約08:30於弘益大學（2號線）或明洞（4號線）上車","搭乘巴士沿京釜高速公路向南1小時抵達水原","9小時行程精心規劃，在遊客高峰前完成華城參觀","巴士配備冷氣及USB充電"],"timeUsed":["在指定首爾上車地點集合（約5分鐘完成上車）","搭乘巴士前往水原（交通順暢時約60分鐘）"],"whyOnRoute":"早上09:30抵達水原，即可在中午遊客高峰（約11:00）前，提早60至90分鐘進入華城。全天行程如鐘錶般精準——城堡→行宮→市場午餐→圖書館→洞窟——將巴士移動距離降至最低，並以洞窟穩定可靠的室內節目作為完美收尾。","visitBasics":{},"convenience":{},"smartNotes":{"tip":"預訂時請確認確切的接送時間與集合地點。城牆步行請攜帶飲用水、防曬乳及舒適的步行鞋，並備妥輕薄外套以備洞窟參觀（全年12°C）。"},"_poi_meta":{"poi_key":"OPS_seoul_pickup_default","verified":false,"match":"operational_default","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational pickup — Seoul departure"},"_role":"pickup"},{"number":2,"time":"≈ 09:30","duration":"60 分鐘","name":"水原華城","category":"聯合國教科文組織世界遺產城堡","description":"**水原華城（수원화성）——1997年列入聯合國教科文組織世界遺產**——韓國唯一保存有完整十冊建築記錄的城牆城市（《華城城役儀軌》，已於2007年另行列入聯合國教科文組織世界記憶名錄）。由正祖大王（정조，朝鮮第22代君主，在位\n\n1776-1800年）主導興建，**1794至1796年歷時2年9個月竣工**——此為正祖遷都計畫，旨在將朝鮮都城自漢陽（首爾）遷至水原，並藉此追思其遭賜死的父親思悼世子。由**丁若鏞（정약용，號茶山）**設計——朝鮮實學（實用學問）學派的代表性學者工程師——融合韓國防禦建築、中國攻城防禦理論與西方新興築城科學。\n\n丁若鏞發明了**舉重機（거중기）滑輪起重裝置**——韓國建築史上首次有記錄使用西式現代工程技術。\n\n**城牆總周長5.74公里，設有41座軍事設施**，其中包括**長安門（北主門）——韓國現存最大的王朝城門**，規模超越首爾崇禮門。\n\n本9小時行程將步行**長安門至華西門（西門，國寶第403號）之間最具攝影魅力的1.2公里路段**——約25至30分鐘步行，途經保存密度最高的軍事建築群。\n\n**華虹門（北水門）**以其橫跨水原川的7座拱橋，成為全區最多人拍攝的建築。**韓服穿著者、每月最後一個星期三、65歲以上長者及6歲以下兒童可免費入場**——對水原家庭一日遊而言是相當實惠的優惠。","highlights":["**1997年列入聯合國教科文組織世界文化遺產**——擁有原版華城城役儀軌建造紀錄的韓國唯一城牆城市","由正祖大王主導，1794至1796年歷時2年9個月建成","由丁若鏞設計，融合韓式、中式與西式築城科學","《華城城役儀軌》——2007年列入聯合國教科文組織世界記憶名錄","城牆周長5.74公里，設有41座軍事設施","長安門（北門）——**韓國現存最大的王朝城門**","長安門至華西門導覽步行1.2公里（攝影景點最密集路段）","華虹門7拱水閘——全區最多人拍攝的建築","韓服穿著者、65歲以上長者及每月最後一個星期三免費入場"],"timeUsed":["巴士於長安門附近下車（約5分鐘）","簡短團體說明（約5分鐘）","步行長安門至華西門（約25至30分鐘）","拍照時間及返回車輛集合（約10分鐘）","可選：華城列車觀光小火車，練武臺↔八達門（單程約30分鐘；成人₩4,000）"],"whyOnRoute":"此為行程的聯合國教科文組織世界遺產核心——韓國唯一現存的城牆城市，由正祖大王主導，1794至1796年建成。長安門至華西門的步行路段在60分鐘的停留時間內，提供了最高密度的保存軍事建築群，完全契合含5個重要站點的9小時行程規模。若完整走完5.74公里的全段城牆，需耗時逾2.5小時，將大幅壓縮當日其他文化遺產與現代景點的時間。就本5站行程而言，華城作為**上午的核心景點**——5.74公里的城牆周長無法在單次造訪中全部走完，因此一日遊格式聚焦於長安門至西將臺的西段（步行約25至30分鐘，保存密度最高）。1801年的**《華城城役儀軌》**建築記錄——自2007年起列入聯合國教科文組織世界記憶名錄——詳載每塊石材、每根梁柱及每位工匠的工資，為韓戰後自1975年起的忠實修復工程提供了重要依據。丁若鏞的**舉重機（거중기）滑輪起重裝置**是全球首次有記錄將西方力學工程應用於朝鮮時代建築工地，較韓國工業機械化早約120年。","visitBasics":{"hours":"城牆步道全天24小時開放；建議參觀時間：夏季09:00-18:00 / 冬季09:00-17:00","closed":"全年開放（華城列車週一休息）","admission":"成人₩1,000 / 青少年₩700 / 兒童₩500（免費：6歲以下兒童、65歲以上長者、韓服穿著者、每月最後一個星期三）","walking":"中等難度——城牆部分路段坡度較陡；城門處設有階梯"},"convenience":{"restroom":"長安門、華西門、八達門、練武臺","parking":"遊覽車於長安門停車場下客"},"smartNotes":{"photo":"**華虹門（北水門）**橫跨水原川的七道拱橋——經典取景地。黃金時刻的**長安門（韓國現存最大王室城門）**。**西將臺（西側指揮所）**俯瞰八達山的日落美景。","facilities":"各主要城門均設有遊客服務中心；全區設有英韓雙語標示","tip":"在行宮廣場租借韓服可免費入場城郭及行宮。長安門→華西門段擁有最高的每公尺文化遺產密度。"},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","caption":"水原華城 — 照片 1","alt":"水原華城 — 圖庫圖片 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","caption":"水原華城 — 照片 2","alt":"水原華城 — 圖庫圖片 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","caption":"水原華城 — 照片 3","alt":"水原華城 — 圖庫圖片 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","caption":"水原華城 — 照片 4","alt":"水原華城 — 圖庫圖片 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","caption":"水原華城 — 照片 5","alt":"水原華城 — 圖庫圖片 5"}]},{"number":3,"time":"≈ 10:45","duration":"60 分鐘","name":"華城行宮","category":"朝鮮王朝離宮","description":"**華城行宮（화성행궁）— 韓國現存規模最大的行宮（離宮）** — 於1789至1796年間，由正祖大王與華城城牆同步興建。\n\n**行宮**是王室出行、戰時避難或舉行特殊典禮時所使用的臨時離宮；華城行宮在規模上超越溫陽、北漢山及南漢山行宮。正祖興建此宮，主要是為了在前往被賜死的父親思悼世子陵寢（顯隆園，今融陵，位於南方4公里處）省墓時得以留宿，**在位期間共計巡幸13次**。\n\n其中最著名的是**1795年的王室巡幸**（隨行人員6,000名、馬匹1,400匹），為惠慶宮洪氏六十壽辰慶典而舉行，全程記載於**《園幸乙卯整理儀軌》，並自2007年起列入聯合國教科文組織世界記憶名錄**。行宮原有**576間（칸，房間／結構灣）**，是一座完整的縮小版王宮。\n\n日本殖民時期（1910-1945年），行宮被改建為水原道立醫院及警察署，遭受大規模破壞。復原工程於1996年啟動；第一期於2003年竣工（奉壽堂、洛南軒、長安軒、維與宅），第二期於2009年完成（於華館御廚、新豐樓城門）。\n\n**重要歷史注記：洛南軒（낙남헌）是唯一一棟自1796年原建至今倖存的建築** — 日本殖民當局雖將其改作警察署辦公室，卻未予拆除。因此，洛南軒是園區內唯一的**正宗原始建築**，其餘一切皆為1996年後復建。\n\n**王室衛隊交接儀式**於新豐樓城門舉行 — **週二至週日上午11:00**，約15分鐘，**免費**。行程安排於10:45抵達，即是為了在符合星期條件時，能即時欣賞11:00的交接儀式。此地曾作為韓劇**《大長今》（2003年）**的拍攝地 — 該劇是朝鮮歷史劇的經典之作，於 MBC 創下約 57% 的最高收視率。","highlights":["**韓國現存規模最大的行宮（離宮）** — 原有576間房","正祖大王為祭奠被賜死的父親思悼世子，13次親赴此地巡幸省墓","**洛南軒 = 唯一保存至今的1796年原始建築**（其餘皆為復建）","**王室衛隊交接儀式 週二至週日上午11:00，於新豐樓城門舉行（免費）**","1795年王室巡幸 — 聯合國教科文組織世界記憶名錄","韓劇《大長今》拍攝地","穿著韓服者及65歲以上長者**免費**入場","**洛南軒（낙남헌）是唯一一棟自1796年原建至今倖存的建築** — 日本殖民時期當局將其改作警察署辦公室，但並未拆除；行宮園區內今日所見的其他所有建築，皆是依據《華城城役儀軌》（自2007年起列入聯合國教科文組織世界記憶名錄）於1996年後復建而成","**576間（칸，房間／結構灣）** = 韓國現存**規模最大**的行宮離宮 — 正祖大王特地興建此宮，以便在前往被賜死的父親思悼世子陵寢（顯隆園，位於南方4公里處）省墓時留宿；正祖於1795至1800年間共計巡幸13次"],"timeUsed":["距華城城牆（華西門一帶）步行約5分鐘","上午11:00王室衛隊交接儀式（週二至週日），約15分鐘","奉壽堂＋洛南軒＋長安軒參觀路線（約30分鐘）","拍照留念＋於車輛旁集合（約10分鐘）","可選擇觀賞新豐樓城門王室衛隊交接儀式（週二至週日上午11:00，約15分鐘，免費 — 視天氣而定）"],"whyOnRoute":"此臨時王室行宮與華城城牆同屬聯合國教科文組織世界遺產範圍，兩地相距步行僅5分鐘。**洛南軒 = 唯一正宗原始建築**（其餘皆為1996年後復建）。建議安排在上午11:00前抵達，以欣賞王室衛隊交接儀式 — 免費、約15分鐘，是本行程表中最具吸引力的免費體驗之一。行宮是華城建設計畫的**歷史與情感核心** — 城牆（1794-1796年）正是環繞行宮而建，專為護衛正祖大王前往父親陵寢的孝道巡幸之旅。在城牆段落參觀之後接續遊覽行宮，可將原本抽象的軍事建築知識，轉化為真實體驗朝鮮王朝宮廷空間的歷史感受：同一座**奉壽堂正殿**，也曾於1795年舉辦正祖母親惠慶宮洪氏六十壽辰的盛大慶典（詳見現存《儀軌班次圖》宮廷畫卷）。此地亦曾出現於多部韓劇的拍攝場景，包括《大長今》（2003年）、《成均館緋聞》（2010年）及《雲畫的月光》（2016年）。**華城城牆＋行宮聯票**售價3,500韓元（分別購票則各為2,500韓元），使行宮成為當日主線行程中高性價比的加選景點。","visitBasics":{"hours":"09:00-18:00（最後入場17:30）；夏季5月至10月夜間開放時間18:00-21:00","closed":"全年開放","admission":"成人1,500 / 青少年1,000 / 兒童700韓元。華城城牆＋行宮聯票3,500韓元。穿著韓服者及65歲以上長者免費","walking":"輕鬆 — 宮殿園區地勢大致平坦，各庭院之間設有部分台階"},"convenience":{"restroom":"位於正門入口、奉壽堂附近及行宮廣場","parking":"華城行宮公共停車場；行宮廣場周邊付費停車場"},"smartNotes":{"photo":"**奉壽堂正殿** + **洛南軒（唯一保存至今的1796年原始建築）** + **新豐樓皇家衛隊換崗儀式（週二至週日上午11:00）**","facilities":"遊客服務中心、行宮廣場韓服租借（4小時15,000–20,000韓元）、往南步行5分鐘可達水原炸全雞餐廳。","tip":"**請準時抵達，觀賞上午11:00的皇家衛隊換崗儀式（週二至週日，免費）**。**洛南軒是歷史上最重要的單一景點** — 唯一未經重建、在日本殖民統治時期拆除行動中倖存下來的建築。請避開週一 — 皇家衛隊換崗儀式僅於週二至週日舉行。"},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","caption":"水原華城 — 照片 1","alt":"水原華城 — 圖庫圖片"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","caption":"水原華城 — 照片 2","alt":"水原華城 — 圖庫圖片"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","caption":"水原華城 — 照片 3","alt":"水原華城 — 圖庫圖片"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","caption":"水原華城 — 照片 4","alt":"水原華城 — 圖庫圖片"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","caption":"水原華城 — 照片 5","alt":"水原華城 — 圖庫圖片"}]},{"number":4,"time":"≈ 12:30","duration":"90分鐘","name":"Starfield圖書館水原店","category":"現代文化地標","description":"**Starfield圖書館水原（별마당 도서관 수원）** — 位於**Starfield水原**館內，這是新世界（Shinsegae）旗艦「第二代」Starfield購物中心，於**2024年1月26日正式開幕**，為第五座Starfield購物中心。總樓地板面積約334,000平方公尺，是繼Starfield河南（Hanam）之後韓國室內面積第二大的購物中心。由**BCHO Partners（趙秉洙建築師事務所）**參與設計——正是原COEX Starfield圖書館（2017年）的設計團隊。\n\n水原館圖書館代表第二代迭代設計，**書架高達22公尺**——為韓國公共空間中最高的圓柱形書架結構之一；圖書館橫跨4個樓層（1F至4F中庭挑高空間），館藏約**70,000冊書籍與雜誌**，涵蓋韓國及國際出版物、期刊、藝術書籍，以及位於4F的兒童專區。\n\n**全程免費對外開放**，開放時間與購物中心相同（每日10:00-22:00）。無需辦理借閱證，免入場費。書籍不提供外借（僅限館內閱覽）。特色亮點：精選韓國獨立音樂及爵士／古典搖滾黑膠唱片的**黑膠唱片視聽休憩區**；**每月輪換中庭藝術展覽**；以及**中央中庭季節性櫻花裝置（3至4月）**，以數千朵粉紅色LED花瓣營造氛圍——是水原春季最受歡迎的拍照打卡景點之一。\n\n鄰近購物中心設施：**B1F Eatopia美食廣場**，匯聚30家以上餐廳；**Aquafield水原水上樂園及韓式溫泉（B1-2F）**須另行購票入場；**玩具王國（4F，韓國最大玩具店）**；**CGV／MEGABOX雙院線影城**。\n\n**Starfield免費接駁巴士**從水原站4號出口出發，每10至15分鐘一班——是銜接大眾運輸的最便捷方式。**行程中的休整站** — 舒適的全室內環境，讓旅客在前往光明洞窟（約30分鐘車程）前重新調整步伐。\n\n**咖啡休息＋圖書館拍照＋逛街購物** — 定位為輕鬆的過渡安排，而非另一個需要高度參與的景點。","highlights":["**新世界旗艦第二代Starfield購物中心——2024年1月26日正式開幕**","BCHO Partners設計（亦為原COEX Starfield圖書館設計者）","**四層樓圖書館，書架高達22公尺** — 為韓國最高書架之一","約70,000冊書籍及雜誌，**免費**開放","黑膠唱片視聽休憩區","櫻花LED花瓣裝置（3至4月）","Eatopia美食廣場、Aquafield水上樂園、玩具王國、CGV＋MEGABOX影城","自水原站4號出口搭乘Starfield免費接駁巴士（約10分鐘）","**屋頂裝置藝術《行星》（The Planets），由加拿大小說家暨設計師道格拉斯·科普蘭（Douglas Coupland）創作** — 為水原館獨有展品（首爾COEX館不設此裝置）；彰顯Starfield水原在新世界圖書館購物中心體系中作為「第二代」旗艦的定位，由**BCHO Partners（趙秉洙）**操刀設計，而非常遭誤指的荷蘭建築事務所MVRDV"],"timeUsed":["從八達門廣場乘坐大型遊覽巴士車程約15分鐘","購物中心及圖書館導覽步行（約45分鐘）","咖啡休息或逛街購物（約20分鐘）","返回大巴集合（約10分鐘）","【可選】黑膠唱片咖啡廳視聽區（5F，約₩18,500，含飲品＋耳機＋黑膠唱機使用；約30至45分鐘）"],"whyOnRoute":"繼城郭、宮殿與市場午餐之後，「現代韓國」的另一面。新世界旗艦第二代Starfield購物中心於2024年1月26日正式開幕；四層樓、書架高達22公尺的圖書館是全館建築亮點。**全室內休整站** — 有效緩衝午後天氣風險，在抵達光明洞窟工業遺產主題終站之前，為各年齡層旅客帶來真正多元的體驗。Starfield圖書館是**大首爾地區（首爾市中心以外）Instagram打卡次數最多的室內空間**（依據2024至25年韓國旅遊媒體調查）— 22公尺書架（相較首爾COEX館的13公尺）橫跨購物中心4F至7F，形成連通的中庭挑高空間。**免費入場、無需會員資格、館內可自由拍照、購物中心全區免費進入** — 零門檻打卡景點，鄰近咖啡廳及餐飲選項（B1F Eatopia美食廣場，30家以上韓式及國際餐廳）。從水原站出發：搭乘Starfield免費接駁巴士（每10至15分鐘從水原站4號出口發車），或搭乘首都圈1號線至華西站（Hwaseo Station）1／4號出口（步行約8分鐘）。購物中心營業時間**每日10:00-22:00**，圖書館於購物中心營業時間內全程開放。","visitBasics":{"hours":"購物中心10:00-22:00；圖書館於購物中心營業時間內全程開放","closed":"每月1至2日公休（通常為週一——請事先上網確認）","admission":"圖書館免費；購物中心全區免費入場；Aquafield水上樂園另行收費約25,000至35,000韓元","walking":"無障礙便利——各樓層均設有手扶梯及電梯；適合輪椅及嬰兒推車進出"},"convenience":{"restroom":"每層樓均設有多個洗手間；附設親子友善設施","parking":"地下停車場約5,000個車位；於商場消費滿30,000韓元可享前3小時免費停車；另設大型巴士停車場供團體使用"},"smartNotes":{"photo":"**圖書館中央中庭設有22公尺高書架**，可從4樓俯瞰。黑膠唱片休息室呈現復古美學風格。中庭春季櫻花裝置藝術（3月至4月）。聖誕樹裝飾（12月）。","facilities":"B1層Eatopia美食廣場、4樓玩具王國、B1至2層Aquafield水上樂園、T-Joy + CGV + MEGABOX電影院、免費Wi-Fi、多語言客戶服務、退稅櫃台。","tip":"**圖書館免費入場** — 超值必訪景點。**22公尺高書架＝韓國最高**（向賓客提及以增添驚喜效果）。**3月至4月櫻花裝置藝術**是季節限定必看亮點。避免週六下午前往（人潮尖峰時段）。請上網確認Starfield每月休館日期。"},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["Starfield official","VisitKorea","Shinsegae press","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield圖書館水原店","caption":"Starfield圖書館水原店 — photo 1","alt":"Starfield圖書館水原店 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield圖書館水原店","caption":"Starfield圖書館水原店 — photo 2","alt":"Starfield圖書館水原店 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield圖書館水原店","caption":"Starfield圖書館水原店 — photo 3","alt":"Starfield圖書館水原店 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield圖書館水原店","caption":"Starfield圖書館水原店 — photo 4","alt":"Starfield圖書館水原店 — gallery image 4"}]},{"number":5,"time":"≈ 15:30","duration":"100 分鐘","name":"光明洞窟","category":"工業遺產主題洞窟","description":"**光明洞窟（광명동굴）** — 原為一座**金、銀、銅、鋅礦山**，開鑿於**1912年日本殖民統治時期**，持續運營60年直至1972年。開採期間共產出黃金52公斤、白銀6,070公斤、銅1,247噸、鋅3,247噸——是日治時代對朝鮮半島規模可觀的礦產開採。 採礦停止後，廢棄的礦道被用作**蝦醬（새우젓）發酵儲存**設施長達約40年——洞窟內穩定的約12°C溫度與高濕度，使其成為韓式醃漬海鮮（醬蟹類）熟成的理想環境。 **光明市於2011年以43億韓元自私人業主手中購入此洞窟**，並於2011年8月重新開放，成為**韓國首個政府所有的洞窟觀光景點**。榮獲**2014年韓國觀光之星獎（韓國旅遊界奧斯卡）**——首個獲此殊榮的市政府開發景點。 **總隧道長度7.8公里**，分佈於多個層級；**對外開放的參觀路線約2公里**，劃分為多個主題分區。**全年恆溫約12°C（54°F）**——夏季天然清涼（深受苦熱遊客青睞），冬季較戶外溫暖。 **請攜帶薄外套。** **主題分區**：**洞窟水族館**（韓國最深的室內淡水水族館）；**酒窖洞窟**（韓國最大地下酒窖，存放200種以上韓國及進口葡萄酒——提供品酒服務，3款酒5,000韓元）；**LED藝術隧道**（200公尺長隧道，設有季節主題燈光——春季櫻花、秋季楓葉、冬季雪景）；**龍丸（Yongmaru）巨龍**（41公尺長玻璃纖維龍——韓國所有洞窟中最高的室內雕塑，最受社群媒體追捧的打卡勝地）；**螢光壁畫**（以天然螢光顏料繪製，僅在紫外線/黑光燈照射下可見）；**音樂廳**（200席、音響效果優化的演出場地）；以及**韓國民間故事洞窟主題樂園**，設有韓國民間故事角色裝置（鬼怪、老虎、兔子）。 曾為拍攝地點：韓劇**《阿爾罕布拉宮的回憶》（2018年）**、**《花遊記》**、**《Doctors》**及多個綜藝節目。**年訪客量約150萬人次**（2024年數據）——京畿道付費旅遊景點前五名之一。 **週一休館。** 週二至週日 09:00–18:00（最後入場 17:00）。成人 10,000 / 青少年 5,000 / 兒童 3,000 韓元。主要路線均可供輪椅通行（平坦路面，設有坡道路段）。 ---","highlights":["**原為金／銀／銅／鋅礦山** — 由日本殖民政府於1912年至1972年間運營","於2011年8月重新開放，成為韓國首個政府所有的洞窟觀光景點","**榮獲2014年韓國觀光之星獎**（韓國旅遊界奧斯卡）","總隧道長度7.8公里；開放公眾參觀路線約2公里","**全年恆溫約12°C** — 請攜帶薄外套","**41公尺玻璃纖維巨龍（龍丸）** — 韓國洞窟內最高室內雕塑","酒窖洞窟 — 韓國最大地下酒窖（200種以上葡萄酒；品酒 5,000 韓元）","LED藝術隧道 ＋ 螢光壁畫 ＋ 音樂廳 ＋ 洞窟水族館","拍攝地點：《阿爾罕布拉宮的回憶》（2018年）、《花遊記》","**週一休館** — 週二至週日 09:00–18:00","主要路線可供輪椅通行"],"timeUsed":["從水原星野Fields搭乘遊覽車至光明，車程約30分鐘","洞窟入口及購票（約10分鐘）","主題分區參觀：水族館 → LED隧道 → 巨龍 → 音樂廳 → 酒窖洞窟 → 民間故事樂園（約70–80分鐘）","可選品酒體驗（約15分鐘，需另付費）","於遊覽車旁集合（約10分鐘）"],"whyOnRoute":"當日工業遺產的核心景點，同時作為**全室內的壓軸行程** — 可有效緩衝午後天氣風險，並呈現韓國最具代表性的洞窟旅遊體驗。從1912年至1972年的採礦歷史，到2011年的重新開放，再到LED藝術改造，這是旅遊目錄中敘事最引人入勝的工業遺產故事。主要路線可供輪椅通行，使其成為當日行程中對行動不便旅客最友善的遺產景點。光明洞窟的**多層次工業遺產敘事**正是其獨特賣點：一座1912年日本殖民時代的金／銀／銅／鋅礦山，運營長達60年（1912–1972年），廢棄後作為蝦醬發酵儲存設施使用約40年（得益於洞窟內**全年恆溫約12°C / 54°F**及高濕度），最終於**2011年由光明市以43億韓元**自私人業主購入，成為**韓國首個政府所有的洞窟觀光景點**，並榮獲2014年韓國觀光之星獎。**開放參觀的2公里路線**（總隧道長度7.8公里）在約1.5至2小時內，涵蓋洞窟水族館 ＋ 200公尺LED藝術隧道 ＋ 酒窖洞窟（韓國最大地下酒窖，存放200種以上韓國及進口葡萄酒）＋ 200席音樂廳 ＋ 41公尺龍丸玻璃纖維巨龍（韓國洞窟內最高室內雕塑）。","visitBasics":{"hours":"週二至週日 09:00–18:00（最後入場 17:00）；7至8月夏季週末延長開放至 19:00","closed":"**週一**休館（若週一為國定假日則照常開放，改為翌日補休）","admission":"成人 10,000 / 青少年 5,000 / 兒童 3,000 韓元；6歲以下兒童及65歲以上長者**免費**","walking":"輕鬆至中等難度 — 主要路線約2公里，大部分為平坦鋪裝洞窟地面；主要路線可供輪椅通行"},"convenience":{"restroom":"位於主入口、洞窟中段（音樂廳區域）及出口處","parking":"大型專用停車場（約1,000個車位）；轎車 2,000 韓元 / 巴士 5,000 韓元；設有團體遊覽車專用停車區"},"smartNotes":{"photo":"**LED藝術隧道**季節主題燈光（春季櫻花、秋季楓葉、冬季雪景）— 最熱門的拍攝區域。**41公尺龍丸巨龍** — 社群媒體病毒式打卡景點。**紫外線燈下的螢光壁畫**。**酒窖葡萄酒瓶牆**，附有韓國葡萄酒生產商標籤。","facilities":"洞窟餐廳（韓式自助餐，約15,000韓元）、附洞窟熟成葡萄酒酒單的咖啡廳、禮品店、葡萄酒洞窟品酒室（5,000韓元品嚐3款葡萄酒）、音樂廳演出時刻表。","tip":"**全年恆溫12°C——即使夏天也請攜帶薄外套**。是**逃離韓國酷暑的絕佳避暑勝地**。**請避開週一**——公休。**葡萄酒品嚐**（5,000韓元品嚐3款）是最被低估的體驗——這些來自地方酒莊的韓國葡萄酒，在首爾根本找不到。最少安排1.5至2小時；若含品酒及音樂廳演出，建議預留2.5小時。"},"_poi_meta":{"poi_key":"gwangmyeong_cave","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-05-21","sources":["VisitKorea","Wikipedia","Gwangmyeong City","KoreaToDo","Korea Tourism Organization (english.visitkorea.or.kr — Gwangmyeong Cave official listing)","Gwangmyeong Cave official (gmcave.gm.go.kr — themed zones + operating hours + admission)","Gwangmyeong City Tourism (gm.go.kr/tour — 2011 city purchase 4.3 billion KRW + Korea''s first govt-owned cave-tourism)","Wikipedia (Gwangmyeong Cave — 1912 Japanese colonial mine + 1972 closure + 7.8 km tunnel total)","Korea Tourism Star Award archive (Gwangmyeong Cave 2014 winner — Best New Tourist Attraction)"]},"image":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","images":["/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp"],"imageCredits":[{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","source":"atoc-korea"},{"url":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp","location":"光明洞窟","caption":"光明洞窟 — photo 1","alt":"光明洞窟 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp","location":"光明洞窟","caption":"光明洞窟 — photo 2","alt":"光明洞窟 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp","location":"光明洞窟","caption":"光明洞窟 — photo 3","alt":"光明洞窟 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp","location":"光明洞窟","caption":"光明洞窟 — photo 4","alt":"光明洞窟 — gallery image 4"}]},{"number":6,"time":"≈ 17:30","duration":"60 分鐘","name":"返回首爾","category":"返回","description":"搭乘遊覽車經由**西海岸高速公路**返回首爾市中心（與早上經由京釜高速公路的去程路線不同——幾何形環狀路線反映出光明市的西部位置相對於水原的南部位置）。於早上出發的相同地點下車（弘益大學站8號出口或明洞站2/4號出口）。依週五傍晚／週末交通狀況，預計抵達時間為**18:30-19:00**。","highlights":["從光明經西海岸高速公路返回","於弘益大學站或明洞站下車","預計抵達時間 18:30-19:00"],"timeUsed":["從光明搭乘遊覽車至首爾（約60分鐘）","於指定地點下車"],"whyOnRoute":"返程安排——從光明走西海岸高速公路，比從水原原路折返走京釜高速公路更為快捷，充分利用當天的地理環狀路線。","visitBasics":{},"convenience":{},"smartNotes":{"tip":"最終抵達時間取決於週五傍晚／週末交通狀況；遇交通壅塞時，下車時間可能延遲15至20分鐘。"},"_poi_meta":{"poi_key":"OPS_return","verified":false,"match":"operational_implicit","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational stop (return)"},"_role":"dropoff"}],"routeFlowStops":[{"name":"首爾","type":"origin","theme":"出發"},{"name":"水原華城","type":"primary","theme":"UNESCO世界遺產城牆"},{"name":"華城行宮","type":"primary","theme":"歷史文化宮殿"},{"name":"星田圖書館水原館","type":"secondary","theme":"現代韓國"},{"name":"光明洞窟","type":"primary","theme":"洞窟"},{"name":"首爾","type":"return","theme":"返回"}],"routePhases":[{"phase":"去程","duration":"約1小時","description":"首爾 → 經京釜高速公路至水原市。"},{"phase":"文化遺產半日遊","duration":"約 3 小時","description":"水原華城城牆與行宮，彼此皆在步行距離之內。"},{"phase":"現代商業中心","duration":"約 1 小時","description":"驅車 15 分鐘前往水原星廣場，參觀圖書館及美食廣場。"},{"phase":"地下壓軸景點","duration":"約 1.5 小時","description":"驅車 30 分鐘向西北前往光明洞窟，欣賞 LED 燈光主題園區。"},{"phase":"返程","duration":"約 1 小時","description":"光明 → 經西海岸高速公路返回首爾。"}],"routeShapeIntro":{"title":"行程脈絡","subtitle":"這是一條以首爾為起點、向南及西南延伸的京畿道三角環線：上午遊覽水原聯合國教科文組織世界遺產古城，下午初段前往水原旗艦現代購物中心，傍晚以光明廢棄金礦改建的主題景區作為壓軸。三種截然不同的公共空間——軍事、商業、工業——橫跨 250 年歷史，盡在一趟遊覽車環線之中。"},"whyTourWorks":{"bestFor":["初次造訪當地的旅客","情侶","成人家庭","習慣全天行程的活躍旅人","希望造訪聯合國教科文組織世界遺產景點的旅客"],"lessIdealFor":["有幽閉恐懼症或害怕密閉空間的旅客（光明洞窟下層空間狹窄、天花板低矮）","無法應對光明洞窟下層主要景點約 180 級上下台階的旅客（無電梯）","行動不便、難以應對城牆陡坡及城門台階的旅客","希望參觀首爾市中心宮殿的遊客——本行程全程位於京畿道境內","必須於週一出行的旅客——光明洞窟週一休館維護"],"routeLogicSections":[{"title":"為什麼這條路線這樣設計","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"比標準水原行程更多元豐富","detail":"大多數水原一日遊行程結合了華城、行宮與星空圖書館——三個景點彼此相距不超過十分鐘。這個版本加入了光明洞窟，那是一處截然不同的景觀（地下空間、藝術主題、全年恆溫12°C），從水原搭乘大眾運輸並不易抵達。"},{"label":"任何天氣皆宜的室內備選方案","detail":"四個主要景點中有兩個——星空圖書館與光明洞窟——完全位於室內且附有空調。城牆步行段夠短，足以應對下雨或夏日高溫。天氣多變時的可靠之選。"},{"label":"免費入場，有償導覽","detail":"星空圖書館可自行免費入場——但有導遊陪同會更有收穫，他能解釋為何一座購物中心要興建圖書館（新世界集團的MZ世代策略）、它與COEX原版有何差異，以及在不打擾讀者的前提下最佳的拍照角度。"},{"label":"比單一主題的一日遊更精彩有趣","detail":"古蹟行程可能讓人感覺疲於奔命，圖書館與購物中心行程又可能過於輕鬆。這份行程刻意切換節奏——聯合國教科文組織認定的城牆、市場美食、現代圖書館，再到LED燈光璀璨的地下主題樂園——讓整天不陷入單一韻律。"}]},{"title":"步行量的實際感受","icon":"footprints","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","items":[{"label":"城牆：最費力的路段","detail":"步行約1公里，途中坡度陡峭，城門處設有階梯。舒適的鞋子不可或缺。攀登後可俯瞰壯闊景色，但不適合輪椅使用者。"},{"label":"光明洞窟：單程約180階梯","detail":"前往下層亮點（紅酒洞窟、黃金瀑布、水族世界）需走階梯，回程亦然。無電梯。行動不便的訪客可留在上層——仍有約40分鐘的參觀內容。"},{"label":"行宮與星空圖書館：輕鬆易行","detail":"行宮與星空圖書館地勢平坦且無障礙，是城牆與洞窟階梯之間輕鬆的步行區段。"}]},{"title":"天氣與季節變化時","icon":"cloud-sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"夏日酷熱：光明洞窟是最佳消暑站","detail":"洞窟內恆溫12°C，使其成為炎熱天氣的避暑停靠點。城牆步行可適度延長陰涼休息時間；市場午餐可移至星空圖書館的室內享用。"},{"label":"冬日嚴寒：進洞窟前記得添加衣物","detail":"12°C在室外更冷的冬天反而顯得格外涼意。即使是夏天，進入光明洞窟也建議帶一件薄外套；冬天則預計需要繼續穿著外層厚衣。"},{"label":"週一不開放","detail":"光明洞窟每週一休館進行維護，當日行程不開放。如需週一出遊，請選擇民俗村或臥牛精舍版本的行程。"}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"費用包含","preview":"首爾來回豪華巴士接送、英語導遊、水原華城……","content":["首爾來回豪華巴士接送、英語導遊、水原華城城牆門票、華城行宮門票、光明洞窟門票。","不含項目：餐食、飲料、洞窟酒莊自選品酒體驗、小費。","星空圖書館免費入場。"]},{"id":"pickup","title":"上下車地點","preview":"弘益大學站（8號出口）約 08:00，或明洞站（2號或4號出口）約 08:30。","content":["弘益大學站（8號出口）約 08:00，或明洞站（2號或4號出口）約 08:30。","請提前 10 分鐘抵達集合地點。","本行程不提供飯店接送，僅設固定集合地點。","遲到者恕不候車，且不予退款。"]},{"id":"walking","title":"步行與地形說明","preview":"中等難度。","content":["中等難度。","城牆步道段需攀爬上坡石階。","光明洞窟下至低層區域須步行約 180 階石梯，返回時同樣需要爬上來——洞內沒有電梯。","請務必穿著包趾舒適步行鞋。","行動能力有明顯限制者不建議參加。"]},{"id":"what","title":"穿著與攜帶物品","preview":"舒適步行鞋（運動鞋或健行鞋）、薄外套——光明洞窟……","content":["舒適步行鞋（運動鞋或健行鞋）、薄外套——光明洞窟全年維持約 12°C，即使夏天入內也會感到涼意。","冬季建議在城牆段穿著保暖厚外套，進洞窟時改換輕薄層次穿搭。","相機、飲用水，以及午餐與街頭小食的現金（預算約 ₩10,000–₩20,000）。"]},{"id":"cancellation","title":"取消政策","preview":"出發前24小時內可免費取消。","content":["出發前24小時內可免費取消。","當日取消及未出現者恕不退款。","行程週一不運營（光明洞窟週一休館）。"]},{"id":"children","title":"兒童及無障礙設施","preview":"兒童通常很喜歡這個行程——洞窟燈光、龍雕塑和水上世界……","content":["兒童通常很喜歡這個行程——洞窟燈光、龍雕塑和水上世界深受家庭旅客歡迎。","城堡步道設有樓梯及高低不平的路面。","洞窟內有180多級台階，不適合行動不便者、推嬰兒車者或有幽閉恐懼症的旅客。"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"查看季節性說明"},"tomorrow":{"temp":"—","label":"查看季節性說明"},"_seasonalSummary":"Suwon and Gwangmyeong track Seoul''s weather closely (about 30 km south/southwest). Plan for hot, humid summers and cold, dry winters; the cave is a constant 12°C year-round, providing relief in summer and shelter in winter.","_seasonalTemperatures":[{"season":"Spring (Mar–May)","range":"5–22°C","notes":"Cherry blossoms along the fortress wall in early–mid April."},{"season":"Summer (Jun–Aug)","range":"22–32°C","notes":"Hot and humid; cave is a cool refuge."},{"season":"Autumn (Sep–Nov)","range":"8–22°C","notes":"Best season — clear skies, mild temperatures."},{"season":"Winter (Dec–Feb)","range":"-5 to 6°C","notes":"Cold winds on the fortress wall; library and cave are climate-controlled."}]},"seasonalVariations":[{"season":"春季","description":"華城城牆沿線盛開櫻花；洞窟推出春季主題燈光裝置。"},{"season":"夏季","description":"洞窟內部維持12°C，是逃離首爾潮濕夏日的熱門去處；夏季舉辦水原華城文化節。"},{"season":"秋季","description":"城牆沿線楓葉紅遍；水原華城文化節於十月盛大舉行。"},{"season":"冬季","description":"城牆積雪是經典拍照場景；洞窟全年舉辦LED光影展，不受天氣影響。"}],"bookingTrustItems":[{"icon":"check-circle","title":"持牌本地營運商","description":"持有全額保險的韓國認證旅遊營運商","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"路線專家","description":"量身打造的行程，而非千篇一律的固定路線","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"嚴選團體規模","description":"依路線最佳化的人數配置","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"立即","title":"即時確認","detail":"附行程摘要的預訂確認通知"},{"timing":"出發前 12 小時","title":"12 小時前提醒","detail":"天氣更新及路線調整通知"},{"timing":"前一天晚上","title":"最終接送資訊","detail":"確切接送時間及司機聯絡方式"},{"timing":"行程當天早上","title":"當日路線注意事項","detail":"依即時狀況進行的早間行前說明"},{"timing":"行程進行中","title":"逐站小提示","detail":"每個景點的即時導覽指引"},{"timing":"行程結束後","title":"行程後續支援","detail":"後續追蹤與推薦建議"}],"staticQuestions":[{"id":"q1","question":"為什麼行程不在週一開放？","answer":"光明洞窟每週一因例行維護而休館。由於洞窟是四大核心景點之一，行程在週一不開團。若您希望在週一出遊，可考慮僅限水原的行程（華城＋民俗村，或華城＋臥牛精舍）。"},{"id":"q2","question":"門票費用包含在內嗎？","answer":"是的——水原華城、華城行宮及光明洞窟的門票均已包含。星空圖書館對所有人免費開放。可選的洞窟酒莊品酒活動及民俗村內的額外項目則需自費。"},{"id":"q3","question":"午餐有包含嗎？","answer":"不包含。午餐通常在星空水原美食廣場的自由時間享用（選擇豐富，約₩10,000–₩20,000），或在華城附近的水原小餐廳用餐（水原式排骨或雞肉料理）。"},{"id":"q4","question":"光明洞窟裡有多少階樓梯？","answer":"前往下層精華景點（酒窟、黃金瀑布、水族世界）約需走下180階，回程同樣需要爬上180階。洞窟內沒有電梯。行動不便或有幽閉空間恐懼的遊客通常僅停留在上層區域。"},{"id":"q5","question":"洞窟內是溫暖還是寒冷？","answer":"偏涼。洞窟內全年維持恆溫12°C（54°F）。夏天時感覺十分清涼舒適；冬天則建議保留一件外套。夏季遊客通常會特別為這一站準備一件薄外套。"},{"id":"q6","question":"這與水原＋民俗村行程有何不同？","answer":"兩條路線均會造訪華城、行宮及星空圖書館。本行程搭配的是光明洞窟（地下LED主題樂園）；民俗村行程則取消洞窟，改訪位於龍仁的韓國民俗村（一座擁有270棟建築的露天文化遺產園區）。若您追求多樣體驗及室內景點，選擇本行程；若偏好深度探索朝鮮時代文化遺產，則選擇民俗村版本。"},{"id":"first-time","question":"這對初次造訪水原與光明的遊客來說是好選擇嗎？","answer":"是的——對於希望在一天之內體驗一處聯合國教科文組織遺址（華城）、一座朝鮮時代宮殿（行宮）、一個地下主題景點（光明洞窟）及一處當代打卡空間（星空圖書館）的旅客而言，這是極佳的初訪首選。行程涵蓋四種截然不同的文化體驗。請注意：本行程不在週一運行（光明洞窟例行維護日）。"},{"id":"walking","question":"步行量大嗎？","answer":"這是一個步行量較大的行程，其中包含一段需爬大量樓梯的路段。華城城牆有陡峭路段及階梯（約步行1公里）。光明洞窟下層精華景點須下行約180階並原路折返——無電梯可搭乘。行宮地形大致平坦，有部分庭院台階。星空圖書館提供完整的電扶梯及電梯設施。全程步行約4公里。請務必穿著舒適的鞋子，尤其在洞窟樓梯段更為重要。"},{"id":"family","question":"這個行程適合家庭出遊嗎？","answer":"適合孩子能應對城牆步行及光明洞窟樓梯的家庭。洞窟是孩子的最愛——有LED燈光場景、水族世界水族館、41公尺長的龍雕塑、地下酒莊（僅限家長）及黃金瀑布。嬰兒車無法在城牆或洞窟的階梯路段使用。洞窟全年12°C的恆溫環境是一個舒適的休息站。"},{"id":"seniors","question":"年長者可以舒適地參加嗎？","answer":"僅建議體力較好、能應對樓梯及密閉空間的活躍長者參加。光明洞窟下層的180階梯沒有電梯替代方案——若無法走樓梯，可選擇停留在上層（約40分鐘的參觀內容）。城牆有陡峭路段，但較平坦的路段可步行通過。行宮及星空圖書館均無障礙設施完善。即使在夏天，進入洞窟前也建議攜帶薄外套。"},{"id":"children","question":"建議的最小適合年齡是幾歲？","answer":"最適合約10歲以上的遊客。城牆地面不平整，洞窟來回各有180階樓梯，且全日行程約長達9小時。若孩子能夠應對樓梯及密閉空間（洞窟下層通道較為狹窄），年齡較小的孩子亦可參加。孩子們通常非常喜愛洞窟內的地下景點——龍雕塑、水族世界、酒窟（僅供觀賞）。水原街頭美食市場適合各年齡層的遊客。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id 在執行時從 Supabase／環境變數解析；不屬於靜態 JSONB 的一部分。","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:00","name":"弘大入口站（8號出口）","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"time":"08:30","name":"明洞站（2號或4號出口）","type":"station","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"弘大入口站（8號出口）","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"name":"明洞站（4號出口）","type":"station","lat":37.56099,"lng":126.98619}],"notes":["請提前10分鐘抵達。遲到者恕不接待，且不予退款。本行程週一停辦（光明洞窟休館）。"]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"coach","duration_hours":9,"region_tags":["gyeonggi_suwon","gyeonggi_gwangmyeong","gyeonggi_goyang"],"theme_tags":["unesco","fortress","cave","modern_landmark"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","gwangmyeong_cave","starfield_library_suwon"],"pace_level":0.8,"walking_level":0.8,"scenic_level":0.7,"photo_level":1,"culture_level":0.8,"relax_level":0.6,"first_time_fit":0.85,"family_fit":0.9,"senior_fit":0.85,"couple_fit":0.95,"solo_traveler_fit":0.85,"active_traveler_fit":0.5,"adult_family_fit":1,"family_with_teens_fit":1,"young_kids_fit":0.85,"senior_active_fit":0.65,"senior_general_fit":0.85,"mobility_friendly_fit":0.7,"stroller_fit":0.7,"one_day_fit":1,"same_day_flight_fit":0.3,"rain_fit":0.85,"value_for_money_fit":0.95,"iconic_landmark_fit":0.95,"cafe_fit":0.85,"food_fit":0.65,"nature_fit":0.4,"beach_fit":0,"nightlife_fit":0.05,"shopping_fit":0.7,"no_shopping_fit":0.5,"local_culture_fit":1,"storytelling_fit":1,"unesco_fit":1,"intangible_heritage_fit":0.4,"indoor_ratio":0.55,"weather_sensitivity":0.4,"comfort_level":0.6,"budget_fit":0.7,"premium_fit":0.45,"small_group_fit":1,"private_fit":0.05,"bus_fit":1,"price_band":"mid","pickup_base":"seoul_central","return_time_band":"17:00-18:30","duration_band":"9h","min_recommended_age":10,"hard_constraints":{"avoidIf":["tight_same_day_departure"],"notIdealFor":["very_low_mobility","stroller_heavy_groups"]},"walking_notes":["Active walking day with some stairs and uneven terrain.","Average fitness expected.","Sturdy shoes with grip recommended."],"keywords":["seoul suwon hwaseong gwangmyeong cave starfield library","korea_mainland day tour","korea_mainland small group"],"synonym_hints":["seoul suwon hwaseong gwangmyeong cave starfield library","korea_mainland sightseeing"],"seasonality":"year_round","pickup_base_normalized":"seoul","vehicle_type_legacy":"bus_coach","anchor_poi_keys":["hwaseong_fortress","hwaseong_haenggung","suwon_nammun_market","starfield_library_suwon","gwangmyeong_cave"],"private_tour_fit":0.05,"customizable_route_fit":0.1,"flexibility_fit":0.3,"fortress_fit":1,"joseon_palace_fit":1,"cave_fit":1,"industrial_heritage_fit":1,"library_fit":1,"modern_architecture_fit":0.85,"street_food_fit":1,"market_fit":1,"k_drama_filming_fit":0.85,"led_art_fit":1,"history_culture_fit":0.95,"wheelchair_accessible_anchor_fit":0.85,"seasonal_fit":0.8,"romantic_fit":0.75,"premium_dining_fit":0.5,"summer_escape_fit":1,"china_mainland_market_fit":0,"korea_domestic_market_fit":0,"taiwan_market_fit":1,"singapore_market_fit":1,"hong_kong_market_fit":1,"china_diaspora_overseas_market_fit":0.95,"se_asia_market_fit":0.95,"us_market_fit":0.85,"europe_market_fit":0.85,"australia_market_fit":0.85,"japan_market_fit":0.85,"suwon_hwaseong_route_fit":1,"suwon_central_anchor_fit":1,"seoul_to_suwon_30min_drive_fit":1,"seoul_central_hotel_pickup_fit":1,"return_to_seoul_central_fit":1,"small_group_format_fit":1,"fixed_schedule_format_fit":1,"unesco_world_heritage_anchor_fit":1,"unesco_world_heritage_1997_inscription_fit":1,"joseon_dynasty_late_18c_anchor_fit":1,"king_jeongjo_filial_piety_anchor_fit":1,"jeong_yak_yong_silhak_anchor_fit":1,"geojunggi_crane_engineering_anchor_fit":1,"uigwe_memory_of_world_2007_anchor_fit":1,"hwaseong_5_74km_perimeter_anchor_fit":1,"hwaseong_41_structures_anchor_fit":1,"naknamheon_only_original_1796_structure_fit":1,"joseon_royal_haenggung_largest_in_korea_fit":1,"royal_guard_changing_ceremony_anch