-- 3) tour_product_offers (default seed offer; insert-if-missing then sync amount)
INSERT INTO public.tour_product_offers (tour_product_page_id, label, amount_minor, currency, is_active, is_default)
SELECT p.id, 'Default (seed)', 5300, 'USD', TRUE, TRUE
  FROM public.tour_product_pages p
 WHERE p.slug = 'seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library' AND p.locale = 'en'
   AND NOT EXISTS (SELECT 1 FROM public.tour_product_offers o WHERE o.tour_product_page_id = p.id AND o.is_default AND o.is_active);
UPDATE public.tour_product_offers o SET amount_minor = 5300, currency = 'USD'
  FROM public.tour_product_pages p
 WHERE o.tour_product_page_id = p.id AND p.slug = 'seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library' AND p.locale = 'en' AND o.is_default AND o.is_active;

COMMIT;

